diff --git a/pkg/storage/unified/search/bleve.go b/pkg/storage/unified/search/bleve.go
--- a/pkg/storage/unified/search/bleve.go
+++ b/pkg/storage/unified/search/bleve.go
@@ -16,16 +16,18 @@ func (b *bleveBackend) BuildIndex(key string) *Index {
-  b.cacheMu.Lock()
-  defer b.cacheMu.Unlock()
-
   if idx, ok := b.cache[key]; ok {
     return idx
   }

   idx := &Index{docs: len(key)}
+  idx.Flush()
+
+  b.cacheMu.Lock()
+  defer b.cacheMu.Unlock()
   b.cache[key] = idx
   return idx
 }

 func (b *bleveBackend) TotalDocs() int {
   total := 0
   for _, idx := range b.cache {
     total += idx.docs
   }
